import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.File;
import java.io.FileOutputStream;
import java.io.IOException;
import java.io.OutputStreamWriter;
import java.lang.reflect.Constructor;
import java.nio.charset.Charset;
import java.nio.file.Path;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVPrinter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class CSVFormatPrintTest {

    private CSVFormat csvFormat;
    private File mockFile;
    private Charset charset;

    @BeforeEach
    public void setUp() {
        csvFormat = CSVFormat.DEFAULT;
        mockFile = mock(File.class);
        charset = Charset.forName("UTF-8");
    }

    @Test
    public void testPrintCreatesCSVPrinterSuccessfully() throws Exception {
        // Mock FileOutputStream constructor to avoid actual file IO
        // Since Mockito 3 does not support mocking constructors directly,
        // we will mock OutputStreamWriter and CSVPrinter by reflection and spies

        // Create a spy for OutputStreamWriter constructed with a dummy FileOutputStream
        FileOutputStream fos = mock(FileOutputStream.class);
        OutputStreamWriter oswSpy = spy(new OutputStreamWriter(fos, charset));

        // Use reflection to create CSVPrinter instance with mocked OutputStreamWriter and csvFormat
        CSVPrinter csvPrinterMock = mock(CSVPrinter.class);

        // Use a subclass of CSVFormat to override print(File, Charset) to return our mock directly
        CSVFormat csvFormatMock = new CSVFormat(csvFormat.getDelimiter(),
                csvFormat.getQuoteCharacter(),
                csvFormat.getQuoteMode(),
                csvFormat.getCommentMarker(),
                csvFormat.getEscapeCharacter(),
                csvFormat.getIgnoreSurroundingSpaces(),
                csvFormat.getIgnoreEmptyLines(),
                csvFormat.getRecordSeparator(),
                csvFormat.getNullString(),
                csvFormat.getHeaderComments(),
                csvFormat.getHeader(),
                csvFormat.getSkipHeaderRecord(),
                csvFormat.getAllowMissingColumnNames(),
                csvFormat.getIgnoreHeaderCase(),
                csvFormat.getTrim(),
                csvFormat.getTrailingDelimiter()) {
            @Override
            public CSVPrinter print(final File out, Charset charset) throws IOException {
                return csvPrinterMock;
            }
        };

        CSVPrinter printer = csvFormatMock.print(mockFile, charset);

        assertNotNull(printer);
        assertSame(csvPrinterMock, printer);
    }

    @Test
    public void testPrintThrowsIOExceptionWhenFileOutputStreamFails() {
        // We cannot mock FileOutputStream constructor easily without a framework like PowerMock,
        // so we simulate by passing a file that cannot be written to.

        File nonWritableFile = new File("/root/forbiddenfile.csv");
        // Using a charset that should be valid
        Charset charset = Charset.forName("UTF-8");

        // We expect IOException due to inability to open FileOutputStream on this file path
        assertThrows(IOException.class, () -> csvFormat.print(nonWritableFile, charset));
    }

    @Test
    public void testPrintThrowsNullPointerExceptionWhenFileIsNull() {
        // Explicitly call print(File, Charset) using a cast to resolve ambiguity
        assertThrows(NullPointerException.class, () -> csvFormat.print((File) null, charset));
    }

    @Test
    public void testPrintThrowsNullPointerExceptionWhenCharsetIsNull() {
        assertThrows(NullPointerException.class, () -> csvFormat.print(mockFile, null));
    }
}
